import { Component, OnInit, computed, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, Router, RouterLink } from '@angular/router';
import { Bill, BillStatus } from '../../core/models';
import { AuthService } from '../../core/services/auth.service';

@Component({
  selector: 'app-bills-list',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './bills-list.component.html',
  styleUrl: './bills-list.component.css',
})
export class BillsListComponent implements OnInit {
  private auth = inject(AuthService);
  private route = inject(ActivatedRoute);
  private router = inject(Router);

  readonly isEditor = this.auth.isEditor;
  readonly statuses: BillStatus[] = ['introduced', 'committee', 'passed', 'signed', 'vetoed'];

  // Filter state — mirrored to query params so deep links restore the view.
  session = signal('');
  status = signal<BillStatus | ''>('');
  sector = signal('');
  q = signal('');

  loading = signal(false);
  error = signal('');

  // Mock data — the mockup_cleaner clears this signal; service_agent wires it to listBills().
  bills = signal<Bill[]>([
    {
      id: 'b1',
      number: 'HB0042',
      title: 'Renewable Energy Tax Incentives',
      summary: 'Establishes tax credits for solar and wind installations across Utah counties.',
      status: 'committee',
      session: 2025,
      sectors: ['energy', 'environment'],
    },
    {
      id: 'b2',
      number: 'SB0110',
      title: 'Rural Broadband Expansion Act',
      summary: 'Funds last-mile fiber deployment to underserved rural districts.',
      status: 'passed',
      session: 2025,
      sectors: ['telecom', 'infrastructure'],
    },
    {
      id: 'b3',
      number: 'HB0203',
      title: 'Water Rights Modernization',
      summary: 'Updates the framework for agricultural and municipal water allocation.',
      status: 'introduced',
      session: 2025,
      sectors: ['agriculture', 'environment'],
    },
    {
      id: 'b4',
      number: 'SB0075',
      title: 'Grid Resilience & Storage Standards',
      summary: 'Mandates battery storage capacity for utility-scale energy providers.',
      status: 'signed',
      session: 2024,
      sectors: ['energy'],
    },
    {
      id: 'b5',
      number: 'HB0301',
      title: 'Prescription Drug Price Transparency',
      summary: 'Requires disclosure of pricing for pharmacy benefit managers.',
      status: 'vetoed',
      session: 2024,
      sectors: ['healthcare'],
    },
    {
      id: 'b6',
      number: 'SB0158',
      title: 'Affordable Housing Density Bonus',
      summary: 'Grants density bonuses to developments reserving affordable units.',
      status: 'committee',
      session: 2025,
      sectors: ['housing', 'real-estate'],
    },
  ]);

  readonly sectors = computed(() => {
    const set = new Set<string>();
    this.bills().forEach((b) => b.sectors.forEach((s) => set.add(s)));
    return Array.from(set).sort();
  });

  readonly filtered = computed(() => {
    const session = this.session().trim();
    const status = this.status();
    const sector = this.sector().trim().toLowerCase();
    const q = this.q().trim().toLowerCase();
    return this.bills().filter((b) => {
      if (session && String(b.session) !== session) return false;
      if (status && b.status !== status) return false;
      if (sector && !b.sectors.includes(sector)) return false;
      if (q && !`${b.number} ${b.title}`.toLowerCase().includes(q)) return false;
      return true;
    });
  });

  ngOnInit(): void {
    const p = this.route.snapshot.queryParamMap;
    this.session.set(p.get('session') ?? '');
    this.status.set((p.get('status') as BillStatus) ?? '');
    this.sector.set(p.get('sector') ?? '');
    this.q.set(p.get('q') ?? '');
  }

  private syncParams(): void {
    this.router.navigate([], {
      relativeTo: this.route,
      queryParams: {
        session: this.session() || null,
        status: this.status() || null,
        sector: this.sector() || null,
        q: this.q() || null,
      },
      queryParamsHandling: 'merge',
      replaceUrl: true,
    });
  }

  setSession(v: string): void {
    this.session.set(v);
    this.syncParams();
  }
  setStatus(v: string): void {
    this.status.set(v as BillStatus | '');
    this.syncParams();
  }
  setSector(v: string): void {
    this.sector.set(v);
    this.syncParams();
  }
  setQuery(v: string): void {
    this.q.set(v);
    this.syncParams();
  }

  clearFilters(): void {
    this.session.set('');
    this.status.set('');
    this.sector.set('');
    this.q.set('');
    this.syncParams();
  }

  readonly hasFilters = computed(
    () => !!(this.session() || this.status() || this.sector() || this.q()),
  );
}
